t.script:
document.addEventListener('DOMContentLoaded', function () {
    var myCarousel = document.querySelector('#novixCategoryCarousel');
    if (myCarousel) {
        new bootstrap.Carousel(myCarousel, {
            interval: 3000,
            ride: 'carousel',
            pause: false,
            wrap: true
        });
    }
});

document.addEventListener('DOMContentLoaded', function () {
    var myCarousel = document.querySelector('#novixCategoryCarousel');
    if (myCarousel) {
        new bootstrap.Carousel(myCarousel, {
            interval: 3000,
            ride: 'carousel',
            pause: false,
            wrap: true
        });
    }
});

 (function () {
  var track  = document.getElementById('novixCatTrack');
  var prev   = document.getElementById('novixCatPrev');
  var next   = document.getElementById('novixCatNext');
  var dotsEl = document.getElementById('novixCatDots');
  if (!track) return;
  var slides  = track.querySelectorAll('.cat-slide');
  var total   = slides.length;
  var current = 0;
  for (var d = 0; d < total; d++) {
    var dot = document.createElement('button');
    dot.className = 'cat-dot' + (d === 0 ? ' active' : '');
    dot.setAttribute('aria-label', 'slide ' + (d + 1));
    (function(idx){ dot.addEventListener('click', function(){ goTo(idx); }); })(d);
    dotsEl.appendChild(dot);
  }
  function goTo(idx) {
    current = (idx + total) % total;
    track.style.transform = 'translateX(' + (current * 100) + '%)';
    dotsEl.querySelectorAll('.cat-dot').forEach(function(dot, i) {
      dot.classList.toggle('active', i === current);
    });
  }
  prev.addEventListener('click', function () { goTo(current - 1); });
  next.addEventListener('click', function () { goTo(current + 1); });
  if (total <= 1) {
    prev.style.display = 'none';
    next.style.display = 'none';
    dotsEl.style.display = 'none';
  }
})();

 (function () {
  var endDate = new Date();
  endDate.setDate(endDate.getDate() + 3);
  endDate.setHours(endDate.getHours() + 14);
  endDate.setMinutes(endDate.getMinutes() + 27);

  function pad(n) { return n < 10 ? '0' + n : '' + n; }

  function tick() {
    var now  = new Date();
    var diff = Math.max(0, endDate - now);
    var d = Math.floor(diff / 86400000);
    var h = Math.floor((diff % 86400000) / 3600000);
    var m = Math.floor((diff % 3600000)  / 60000);
    var s = Math.floor((diff % 60000)    / 1000);
    var dEl = document.getElementById('pbDays');
    var hEl = document.getElementById('pbHours');
    var mEl = document.getElementById('pbMins');
    var sEl = document.getElementById('pbSecs');
    if (dEl) dEl.textContent = pad(d);
    if (hEl) hEl.textContent = pad(h);
    if (mEl) mEl.textContent = pad(m);
    if (sEl) sEl.textContent = pad(s);
  }

  tick();
  setInterval(tick, 1000);
})();
